#include<bits/stdc++.h>
using namespace std;
int fail[1000010],flag[1000010],in[1000010],son[1000010][31],tot=1;
int res[1000010];
long long mod=998244353;
void insert(string s,int id)
{
    int p=1,len=s.size();
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'0';
        if(!son[p][x])
        {
            son[p][x]=++tot;
        }
        p=son[p][x];
    }
    flag[p]=1;
}
void getfail()
{
    for(int i=0;i<10;i++)
    {
        son[0][i]=1;
    }
    queue<int> q;
    q.push(1);
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        flag[t]|=flag[fail[t]];
        for(int i=0;i<10;i++)
        {
            if(son[t][i])
            {
                fail[son[t][i]]=son[fail[t]][i];
                in[son[fail[t]][i]]++;
                q.push(son[t][i]);
            }
            else
            {
                son[t][i]=son[fail[t]][i];
            }
        }
    }
}
string s[1000010];
struct matrix
{
    long long a[22][22];
    matrix()
    {
        memset(a,0,sizeof(a));
    }
    friend matrix operator*(const matrix&a,const matrix&b)
    {
        matrix c;
        for(long long i=0;i<=21;i++)
        {
            for(long long j=0;j<=21;j++)
            {
                for(long long k=0;k<=21;k++)
                {
                    c.a[i][j]+=1ll*(a.a[i][k]%mod)*(b.a[k][j]%mod)%mod;
                    c.a[i][j]%=mod;
                }
            }
        }
        return c;
    }
}base,ans;
void fastpow(long long y)
{
    ans.a[1][1]=1;
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*base;
        }
        base=base*base;
        y/=2;
    }
}
int main()
{
    int n,k=1;
    scanf("%d%*d%lld",&n,&mod);
    for(int i=1;i<=k;i++)
    {
        cin>>s[i];
        insert(s[i],i);
    }
    getfail();
    for(int i=1;i<=tot;i++)
    {
        if(!flag[i])
        {
            for(int j=0;j<10;j++)
            {
                int v=son[i][j];
                if(!flag[v])
                {
                    base.a[i][v]++;
                }
            }
        }
    }
    fastpow(n);
    long long ans1=0;
    for(int i=1;i<=tot;i++)
    {
        ans1+=ans.a[1][i];
        ans1%=mod;
    }
    printf("%lld",ans1);
    return 0;
}
